'use client'
import { cn } from '@cascivo/core'
import type { InputHTMLAttributes } from 'react'
import styles from './slider.module.css'

export interface SliderProps extends Omit<InputHTMLAttributes<HTMLInputElement>, 'type'> {
  label?: string
}

export function Slider({
  label,
  className,
  id,
  min = 0,
  max = 100,
  step = 1,
  disabled,
  ...props
}: SliderProps) {
  const sliderId =
    id ?? (label ? `cascade-slider-${label.toLowerCase().replace(/\s+/g, '-')}` : undefined)

  return (
    <div className={cn(styles['wrapper'], className)} data-disabled={disabled || undefined}>
      {label && (
        <label className={styles['label']} htmlFor={sliderId}>
          {label}
        </label>
      )}
      <input
        id={sliderId}
        type="range"
        min={min}
        max={max}
        step={step}
        disabled={disabled}
        className={styles['slider']}
        {...props}
      />
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);

    &[data-disabled] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .label {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-snug);
  }

  .slider {
    appearance: none;
    inline-size: 100%;
    block-size: 1.25rem;
    background: transparent;
    cursor: pointer;

    &:disabled {
      cursor: not-allowed;
    }

    &:focus-visible {
      outline: none;
    }
  }

  /* Track + thumb need vendor-specific pseudo-elements */
  @supports selector(::-webkit-slider-runnable-track) {
    .slider::-webkit-slider-runnable-track {
      block-size: 0.375rem;
      border-radius: var(--cascivo-radius-full);
      background-color: var(--cascivo-color-border-strong);
    }

    .slider::-webkit-slider-thumb {
      appearance: none;
      margin-block-start: -0.4375rem;
      inline-size: 1.25rem;
      block-size: 1.25rem;
      border-radius: var(--cascivo-radius-full);
      background-color: var(--cascivo-color-accent);
      border: 2px solid var(--cascivo-color-surface);
      box-shadow: var(--cascivo-shadow-sm);
    }

    .slider:focus-visible::-webkit-slider-thumb {
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  @supports selector(::-moz-range-track) {
    .slider::-moz-range-track {
      block-size: 0.375rem;
      border-radius: var(--cascivo-radius-full);
      background-color: var(--cascivo-color-border-strong);
    }

    .slider::-moz-range-thumb {
      inline-size: 1.25rem;
      block-size: 1.25rem;
      border-radius: var(--cascivo-radius-full);
      background-color: var(--cascivo-color-accent);
      border: 2px solid var(--cascivo-color-surface);
      box-shadow: var(--cascivo-shadow-sm);
    }

    .slider:focus-visible::-moz-range-thumb {
      box-shadow: var(--cascivo-focus-ring);
    }
  }
}

@media (forced-colors: active) {
  .slider::-webkit-slider-thumb {
    border: 2px solid ButtonText;
    background-color: ButtonText;
  }

  .slider:focus-visible::-webkit-slider-thumb {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }

  .slider::-moz-range-thumb {
    border: 2px solid ButtonText;
    background-color: ButtonText;
  }

  .slider:focus-visible::-moz-range-thumb {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
